 55тЖТ/**
 56тЖТ * "Deck Search": A dialog allowing the user to select a deck from a list of decks.
 57тЖТ *
 58тЖТ * * Allows filtering of visible decks based on name (searching): [DecksFilter]
 59тЖТ * * Allows adding a new deck: [showDeckDialog]
 60тЖТ * * Allows adding a subdeck via long-pressing a deck: [showSubDeckDialog]
 61тЖТ *
 62тЖТ * It is opened when the user wants a deck in stats, browser or note editor.
 63тЖТ *
 64тЖТ * @see SelectableDeck The data that is displayed
 65тЖТ */
 66тЖТ@NeedsTest("simulate 'don't keep activities'")
 67тЖТopen class DeckSelectionDialog : AnalyticsDialogFragment() {
 68тЖТ    private var mDialog: MaterialDialog? = null
 69тЖТ    override fun onCreate(savedInstanceState: Bundle?) {
 70тЖТ        super.onCreate(savedInstanceState)
 71тЖТ        isCancelable = true
 72тЖТ    }
 73тЖТ
 74тЖТ    @Suppress("Deprecation") // Material dialog neutral button deprecation
 75тЖТ    override fun onCreateDialog(savedInstanceState: Bundle?): Dialog {
 76тЖТ        val dialogView = LayoutInflater.from(activity)
 77тЖТ            .inflate(R.layout.deck_picker_dialog, null, false)
 78тЖТ        val summary = dialogView.findViewById<TextView>(R.id.deck_picker_dialog_summary)
 79тЖТ        val arguments = requireArguments()
 80тЖТ        if (getSummaryMessage(arguments) == null) {
 81тЖТ            summary.visibility = View.GONE
 82тЖТ        } else {
 83тЖТ            summary.visibility = View.VISIBLE
 84тЖТ            summary.text = getSummaryMessage(arguments)
 85тЖТ        }
 86тЖТ        val recyclerView: RecyclerView = dialogView.findViewById(R.id.deck_picker_dialog_list)
 87тЖТ        recyclerView.requestFocus()
 88тЖТ        val deckLayoutManager: RecyclerView.LayoutManager = LinearLayoutManager(requireActivity())
 89тЖТ        recyclerView.layoutManager = deckLayoutManager
 90тЖТ        val dividerItemDecoration = DividerItemDecoration(recyclerView.context, DividerItemDecoration.VERTICAL)
 91тЖТ        recyclerView.addItemDecoration(dividerItemDecoration)
 92тЖТ        val decks: List<SelectableDeck> = getDeckNames(arguments)
 93тЖТ        val adapter = DecksArrayAdapter(decks)
 94тЖТ        recyclerView.adapter = adapter
 95тЖТ        adjustToolbar(dialogView, adapter)
 96тЖТ        val args = requireArguments()
 97тЖТ        if (args.containsKey("currentDeckId")) {
 98тЖТ            val did = args.getLong("currentDeckId")
 99тЖТ            recyclerView.scrollToPosition(getPositionOfDeck(did, adapter.getCurrentlyDisplayedDecks()))
100тЖТ        }
101тЖТ        mDialog = MaterialDialog(requireActivity())
102тЖТ            .negativeButton(R.string.dialog_cancel)
103тЖТ            .customView(view = dialogView, noVerticalPadding = true)
104тЖТ        if (arguments.getBoolean(KEEP_RESTORE_DEFAULT_BUTTON)) {
105тЖТ            (mDialog as MaterialDialog).positiveButton(R.string.restore_default) {
106тЖТ                onDeckSelected(null)
107тЖТ            }
108тЖТ        }
109тЖТ        return mDialog!!
110тЖТ    }
111тЖТ
112тЖТ    private fun getPositionOfDeck(did: DeckId, decks: List<SelectableDeck>) =
113тЖТ        decks.indexOfFirst { it.deckId == did }
114тЖТ
115тЖТ    private fun getSummaryMessage(arguments: Bundle): String? {
116тЖТ        return arguments.getString(SUMMARY_MESSAGE)
117тЖТ    }
118тЖТ
119тЖТ    private fun getDeckNames(arguments: Bundle): ArrayList<SelectableDeck> =
120тЖТ        BundleCompat.getParcelableArrayList(arguments, DECK_NAMES, SelectableDeck::class.java)!!
121тЖТ
122тЖТ    private val title: String
123тЖТ        get() = requireArguments().getString(TITLE)!!
124тЖТ
125тЖТ    private fun adjustToolbar(dialogView: View, adapter: DecksArrayAdapter) {
126тЖТ        val toolbar: Toolbar = dialogView.findViewById(R.id.deck_picker_dialog_toolbar)
127тЖТ        toolbar.title = title
128тЖТ        toolbar.inflateMenu(R.menu.deck_picker_dialog_menu)
129тЖТ        val searchItem = toolbar.menu.findItem(R.id.deck_picker_dialog_action_filter)
130тЖТ        val searchView = searchItem.actionView as SearchView
131тЖТ        searchView.queryHint = getString(R.string.deck_picker_dialog_filter_decks)
132тЖТ        searchView.setOnQueryTextListener(object : SearchView.OnQueryTextListener {
133тЖТ            override fun onQueryTextSubmit(query: String): Boolean {
134тЖТ                searchView.clearFocus()
135тЖТ                return true
136тЖТ            }
137тЖТ
138тЖТ            override fun onQueryTextChange(newText: String): Boolean {
139тЖТ                adapter.filter.filter(newText)
140тЖТ                return true
141тЖТ            }
142тЖТ        })
143тЖТ        val addDecks = toolbar.menu.findItem(R.id.deck_picker_dialog_action_add_deck)
144тЖТ        addDecks.setOnMenuItemClickListener {
145тЖТ            // creating new deck without any parent deck
146тЖТ            showDeckDialog()
147тЖТ            true
148тЖТ        }
149тЖТ    }
150тЖТ
151тЖТ    private fun showSubDeckDialog(parentDeckPath: String) {
152тЖТ        launchCatchingTask {
153тЖТ            val parentId = withCol { decks.id(parentDeckPath) }
154тЖТ            val createDeckDialog = CreateDeckDialog(requireActivity(), R.string.create_subdeck, CreateDeckDialog.DeckDialogType.SUB_DECK, parentId)
155тЖТ            createDeckDialog.setOnNewDeckCreated { id: Long? ->
156тЖТ                // a sub deck was created
157тЖТ                launchCatchingTask {
158тЖТ                    val name = withCol {
159тЖТ                        decks.name(id!!)
160тЖТ                    }
161тЖТ                    selectDeckWithDeckName(name)
162тЖТ                }
163тЖТ            }
164тЖТ            createDeckDialog.showDialog()
165тЖТ        }
166тЖТ    }
167тЖТ
168тЖТ    private fun showDeckDialog() {
169тЖТ        val createDeckDialog = CreateDeckDialog(requireActivity(), R.string.new_deck, CreateDeckDialog.DeckDialogType.DECK, null)
170тЖТ        // todo
171тЖТ        // setOnNewDeckCreated parameter to be made non null
172тЖТ        createDeckDialog.setOnNewDeckCreated { id: Long? ->
173тЖТ            // a deck was created
174тЖТ            launchCatchingTask {
175тЖТ                val name = withCol { decks.name(id!!) }
176тЖТ                selectDeckWithDeckName(name)
177тЖТ            }
178тЖТ        }
179тЖТ        createDeckDialog.showDialog()
180тЖТ    }
181тЖТ
182тЖТ    /**
183тЖТ     * Create the deck if it does not exists.
184тЖТ     * If name is valid, send the deck with this name to listener and close the dialog.
185тЖТ     */
186тЖТ    private fun selectDeckWithDeckName(deckName: String) {
187тЖТ        launchCatchingTask {
188тЖТ            val id = withCol { decks.id(deckName) }
189тЖТ            val dec = SelectableDeck(id, deckName)
190тЖТ            selectDeckAndClose(dec)
191тЖТ        }
192тЖТ    }
193тЖТ
194тЖТ    /**
195тЖТ     * @param deck deck sent to the listener.
196тЖТ     */
197тЖТ    private fun onDeckSelected(deck: SelectableDeck?) {
198тЖТ        deckSelectionListener!!.onDeckSelected(deck)
199тЖТ    }
200тЖТ
201тЖТ    @KotlinCleanup("Use a factory here")
202тЖТ    var deckSelectionListener: DeckSelectionListener? = null
203тЖТ        get() {
204тЖТ            if (field != null) {
205тЖТ                return field
206тЖТ            }
207тЖТ            val activity: Activity = requireActivity()
208тЖТ            if (activity is DeckSelectionListener) {
209тЖТ                return activity
210тЖТ            }
211тЖТ            val parentFragment = parentFragment
212тЖТ            if (parentFragment is DeckSelectionListener) {
213тЖТ                return parentFragment
214тЖТ            }
215тЖТ            throw IllegalStateException("Neither activity or parent fragment were a selection listener")
216тЖТ        }
217тЖТ
218тЖТ    /**
219тЖТ     * Same action as pressing on the deck in the list. I.e. send the deck to listener and close the dialog.
220тЖТ     */
221тЖТ    protected fun selectDeckAndClose(deck: SelectableDeck) {
222тЖТ        onDeckSelected(deck)
223тЖТ        mDialog!!.dismiss()
224тЖТ    }
225тЖТ
226тЖТ    protected fun displayErrorAndCancel() {
227тЖТ        mDialog!!.dismiss()
228тЖТ    }
229тЖТ
230тЖТ    open inner class DecksArrayAdapter(deckNames: List<SelectableDeck>) : RecyclerView.Adapter<DecksArrayAdapter.ViewHolder>(), Filterable {
231тЖТ        inner class ViewHolder(private val deckTextView: TextView) : RecyclerView.ViewHolder(deckTextView) {
232тЖТ            var deckName: String = ""
233тЖТ            private var deckID: Long = -1L
234тЖТ
235тЖТ            fun setDeck(deck: SelectableDeck) {
236тЖТ                deckName = deck.name
237тЖТ                deckTextView.text = deck.displayName
238тЖТ                deckID = deck.deckId
239тЖТ            }
240тЖТ
241тЖТ            init {
242тЖТ                deckTextView.setOnClickListener {
243тЖТ                    selectDeckByNameAndClose(deckName)
244тЖТ                }
245тЖТ                deckTextView.setOnLongClickListener { // creating sub deck with parent deck path
246тЖТ                    if (deckID == DeckSpinnerSelection.ALL_DECKS_ID) {
247тЖТ                        context?.let { showThemedToast(it, R.string.cannot_create_subdeck_for_all_decks, true) }
248тЖТ                    } else {
249тЖТ                        showSubDeckDialog(deckName)
250тЖТ                    }
251тЖТ                    true
252тЖТ                }
253тЖТ            }
254тЖТ        }
255тЖТ
256тЖТ        private val mAllDecksList = ArrayList<SelectableDeck>()
257тЖТ        private val mCurrentlyDisplayedDecks = ArrayList<SelectableDeck>()
258тЖТ        protected fun selectDeckByNameAndClose(deckName: String) {
259тЖТ            for (d in mAllDecksList) {
260тЖТ                if (d.name == deckName) {
261тЖТ                    selectDeckAndClose(d)
262тЖТ                    return
263тЖТ                }
264тЖТ            }
265тЖТ            displayErrorAndCancel()
266тЖТ        }
267тЖТ
268тЖТ        override fun onCreateViewHolder(parent: ViewGroup, viewType: Int): ViewHolder {
269тЖТ            val v = LayoutInflater.from(parent.context)
270тЖТ                .inflate(R.layout.deck_picker_dialog_list_item, parent, false)
271тЖТ            return ViewHolder(v.findViewById(R.id.deck_picker_dialog_list_item_value))
272тЖТ        }
273тЖТ
274тЖТ        override fun onBindViewHolder(holder: ViewHolder, position: Int) {
275тЖТ            val deck = mCurrentlyDisplayedDecks[position]
276тЖТ            holder.setDeck(deck)
277тЖТ        }
278тЖТ
279тЖТ        override fun getItemCount(): Int {
280тЖТ            return mCurrentlyDisplayedDecks.size
281тЖТ        }
282тЖТ
283тЖТ        override fun getFilter(): Filter {
284тЖТ            return DecksFilter()
285тЖТ        }
286тЖТ
287тЖТ        fun getCurrentlyDisplayedDecks(): List<SelectableDeck> {
288тЖТ            return mCurrentlyDisplayedDecks
289тЖТ        }
290тЖТ
291тЖТ        private inner class DecksFilter : TypedFilter<SelectableDeck>(mAllDecksList) {
292тЖТ            override fun filterResults(constraint: CharSequence, items: List<SelectableDeck>): List<SelectableDeck> {
293тЖТ                val filterPattern = constraint.toString().lowercase(Locale.getDefault()).trim { it <= ' ' }
294тЖТ                return items.filter {
295тЖТ                    it.name.lowercase(Locale.getDefault()).contains(filterPattern)
296тЖТ                }
297тЖТ            }
298тЖТ
299тЖТ            override fun publishResults(constraint: CharSequence?, results: List<SelectableDeck>) {
300тЖТ                mCurrentlyDisplayedDecks.apply {
301тЖТ                    clear()
302тЖТ                    addAll(results)
303тЖТ                    sort()
304тЖТ                }
305тЖТ                notifyDataSetChanged()
306тЖТ            }
307тЖТ        }
308тЖТ
309тЖТ        init {
310тЖТ            mAllDecksList.addAll(deckNames)
311тЖТ            mCurrentlyDisplayedDecks.addAll(deckNames)
312тЖТ            mCurrentlyDisplayedDecks.sort()
313тЖТ        }
314тЖТ    }
315тЖТ
316тЖТ    /**
317тЖТ     * @param deckId Either a deck id or ALL_DECKS_ID
318тЖТ     * @param name Name of the deck, or localization of "all decks"
319тЖТ     */
320тЖТ    @Parcelize
321тЖТ    class SelectableDeck(val deckId: DeckId, val name: String) : Comparable<SelectableDeck>, Parcelable {
322тЖТ        /**
323тЖТ         * The name to be displayed to the user. Contains
324тЖТ         * only the sub-deck name with proper indentation
325тЖТ         * rather than the entire deck name.
326тЖТ         * Eg: foo::bar -> \t\tbar
327тЖТ         */
328тЖТ        @IgnoredOnParcel
329тЖТ        val displayName: String by lazy {
330тЖТ            val nameArr = name.split("::")
331тЖТ            "\t\t".repeat(nameArr.size - 1) + nameArr[nameArr.size - 1]
332тЖТ        }
333тЖТ
334тЖТ        constructor(d: DeckNameId) : this(d.id, d.name)
335тЖТ
336тЖТ        /** "All decks" comes first. Then usual deck name order.  */
337тЖТ        override fun compareTo(other: SelectableDeck): Int {
338тЖТ            if (deckId == ALL_DECKS_ID) {
339тЖТ                return if (other.deckId == ALL_DECKS_ID) {
340тЖТ                    0
341тЖТ                } else {
342тЖТ                    -1
343тЖТ                }
344тЖТ            }
345тЖТ            return if (other.deckId == ALL_DECKS_ID) {
346тЖТ                1
347тЖТ            } else {
348тЖТ                DeckNameComparator.INSTANCE.compare(name, other.name)
349тЖТ            }
350тЖТ        }
351тЖТ
352тЖТ        companion object {
353тЖТ            /**
354тЖТ             * @param filter A method deciding which deck to add
355тЖТ             * @return the list of all SelectableDecks from the collection satisfying filter
356тЖТ             */
357тЖТ            fun fromCollection(c: Collection, includeFiltered: Boolean): List<SelectableDeck> {
358тЖТ                val all = c.decks.allNamesAndIds(includeFiltered = includeFiltered)
359тЖТ                val ret: MutableList<SelectableDeck> = ArrayList(all.size)
360тЖТ                for (d in all) {
361тЖТ                    ret.add(SelectableDeck(d))
362тЖТ                }
363тЖТ                return ret
364тЖТ            }
365тЖТ        }
366тЖТ    }
367тЖТ
368тЖТ    fun interface DeckSelectionListener {
369тЖТ        fun onDeckSelected(deck: SelectableDeck?)
370тЖТ    }
371тЖТ
372тЖТ    companion object {
373тЖТ        const val ALL_DECKS_ID = 0L
374тЖТ        private const val SUMMARY_MESSAGE = "summaryMessage"
375тЖТ        private const val TITLE = "title"
376тЖТ        private const val KEEP_RESTORE_DEFAULT_BUTTON = "keepRestoreDefaultButton"
377тЖТ        private const val DECK_NAMES = "deckNames"
378тЖТ
379тЖТ        /**
380тЖТ         * A dialog which handles selecting a deck
381тЖТ         */
382тЖТ        fun newInstance(title: String, summaryMessage: String?, keepRestoreDefaultButton: Boolean, decks: List<SelectableDeck>): DeckSelectionDialog {
383тЖТ            val f = DeckSelectionDialog()
384тЖТ            val args = Bundle()
385тЖТ            args.putString(SUMMARY_MESSAGE, summaryMessage)
386тЖТ            args.putString(TITLE, title)
387тЖТ            args.putBoolean(KEEP_RESTORE_DEFAULT_BUTTON, keepRestoreDefaultButton)
388тЖТ            args.putParcelableArrayList(DECK_NAMES, ArrayList(decks))
389тЖТ            f.arguments = args
390тЖТ            return f
391тЖТ        }
392тЖТ    }
393тЖТ}
